import React from "react";
import breadcrumb_img from "../../images/breadbg1.jpg"

const Breadcrumb = () =>{
    return(
        <>
            <section class="breadcrumb-part" data-stellar-offset-parent="true" data-stellar-background-ratio="0.5" style={{backgroundImage:`url(${breadcrumb_img})`}}>
                <div class="container">
                    <div class="breadcrumb-inner">
                        <h2>SHOP</h2>
                        <a href="#">Home</a>
                        <span>Shop</span>
                    </div>
                </div>
            </section>
        </>
    )
}

export default Breadcrumb;
